 // ─── BODY FX ─── full page content (AR)
 'bs.bodyfx.name': 'Body FX',
 'bs.bodyfx.eyebrow': 'نحت الجسم',
 'bs.bodyfx.hero.title': 'Body FX لإذابة الدهون',
 'bs.bodyfx.hero.tagline': 'جهاز InMode غير جراحي لنحت الجسم — تقليل الدهون، تحسين السيلوليت، وشد البشرة بدون إبر أو جراحة أو فترة راحة.',
 'bs.bodyfx.about.eyebrow': 'نبذة',
 'bs.bodyfx.about.title': 'إيه هو Body FX؟',
 'bs.bodyfx.about.body': 'Body FX جهاز غير جراحي لنحت وتنسيق الجسم من شركة InMode. الجهاز تصنيع شركة InMode. بيدمج 3 تقنيات قوية في جهاز واحد: تسخين بالترددات الراديوية (RF)، ضغط سلبي (شفط)، ونبضات عالية الفولتية، وكلهم بيشتغلوا مع بعض عشان ينسّقوا الجسم، يحسّنوا مظهر السيلوليت، ويشدوا الجلد المترهل. Body FX بينسّق ويشكّل المنطقة — يعني هو علاج تنسيق وشكل، مش علاج تخسيس. على عكس الخيارات الجراحية أو المتدخلة، Body FX مش محتاج إبر ولا جراحة ولا تخدير ولا وقت راحة — تقدري تيجي، تعملي الجلسة، وتخرجي ترجعي يومك العادي. الجهاز معتمد من FDA ومعترف بيه عالميًا كمنصة آمنة وفعّالة لنحت الجسم من غير جراحة. Body FX بيشتغل بأفضل شكل كجزء من سلسلة جلسات منظمة، وكل جلسة بتبني على اللي قبلها عشان تنسّق شكل المنطقة تدريجيًا، تحسّن ملمس الجلد، وتنحت الجسم على مدار الوقت.',
 'bs.bodyfx.benefits.eyebrow': 'ليه بيشتغل',
 'bs.bodyfx.benefits.title': 'الفوائد والنتائج',
 'bs.bodyfx.benefit.1': 'تقليل الدهون من غير جراحة في المناطق العنيدة.',
 'bs.bodyfx.benefit.2': 'تحسن واضح في مظهر السيلوليت.',
 'bs.bodyfx.benefit.3': 'بيشد الجلد المترهل في الجسم — خصوصًا بعد الولادة أو بعد نزول الوزن.',
 'bs.bodyfx.benefit.4': 'بينعّم ملمس الجلد في البطن والفخذين والذراعين والمؤخرة.',
 'bs.bodyfx.benefit.5': 'بيحفّز إنتاج الكولاجين والإيلاستين الطبيعي.',
 'bs.bodyfx.benefit.6': 'من غير ألم — معظم الحالات بتوصفه بإحساس مساج دافي مع شفط.',
 'bs.bodyfx.benefit.7': 'من غير وقت راحة — ترجعي حياتك العادية على طول.',
 'bs.bodyfx.benefit.8': 'آمن لكل درجات لون البشرة — من غير خطر تصبغات.',
 'bs.bodyfx.benefit.9': 'بيعالج مناطق زي البطن والجناب والفخذين والركب والذراعين والضهر والمؤخرة.',
 'bs.bodyfx.benefit.10': 'مثالي كجلسات المتابعة للحفاظ على النتيجة بعد العمليات الجراحية (شفط الدهون، BodyTite، شد البطن).',
 'bs.bodyfx.benefit.11': 'النتيجة بتفضل تتحسن على مدار أسابيع وشهور مع إعادة بناء الكولاجين.',
 'bs.bodyfx.process.eyebrow': 'المراحل',
