 'bs.hifubody.who.eyebrow': 'مناسب لمين',
 'bs.hifubody.who.title': 'العلاج مناسب لمين؟',
 'bs.hifubody.who.1': 'اللي عندها ترهل بسيط لمتوسط في جلد الجسم (البطن، الذراعين، الفخذين، المؤخرة، الركب).',
 'bs.hifubody.who.2': 'السيدات بعد الولادة اللي عندها جلد بطن مترهل (مش محتاج جراحة).',
