 // ─── VOTIVA (intimate aesthetic) ─── AR
 'treatment.votiva.name': 'فوتيفا',
 'treatment.votiva.short': 'تجميل المنطقة الحساسة بدون جراحة — شد، علاج سلس البول، واستعادة ما بعد الولادة.',
 'treatment.votiva.badge': 'صحة المرأة',
 'votiva.eyebrow': 'صحة المرأة الحميمية',
 'votiva.title': 'Votiva — العلاجات النسائية الحميمة',
 'votiva.tagline': 'علاج نسائي حميم بدون جراحة — مريح، خاص، وبإشراف طبي.',
 'votiva.about.eyebrow': 'نبذة',
 'votiva.about.title': 'إيه هي فوتيفا؟',
 'votiva.about.p1': 'فوتيفا جهاز معتمد من FDA بيستخدم طاقة الموجات الراديوية لعلاج المخاوف الحميمية عند المرأة برفق — بدون جراحة، بدون فترة نقاهة، وبدون تخدير. بيشتغل من خلال تدفئة الأنسجة الداخلية والخارجية لتحفيز إنتاج الكولاجين، تحسين الشد، واستعادة الراحة.',
 'votiva.about.p2': 'في هوليوود كلينك، جلسات فوتيفا بتتم على يد أخصائيات معتمدات في بيئة خاصة بالكامل. الإجراء مريح، سريع (عادةً 30 دقيقة)، وتقدري ترجعي لحياتك اليومية فوراً — بما في ذلك اليوم التالي.',
 'votiva.privacy.title': 'الخصوصية والسرية الكاملة',
 'votiva.privacy.text': 'كل الاستشارات والعلاجات بتتم في خصوصية تامة، على يد طبيبات في غرف مخصصة بسرية كاملة. بنفهم الطبيعة الشخصية للعناية الحميمية.',
 'votiva.who.eyebrow': 'مناسبة لمين',
 'votiva.who.title': 'إمتى فوتيفا تقدر تساعد',
 'votiva.who.subtitle': 'فوتيفا بتعالج مخاوف حميمية شائعة بتمر بيها أغلب النساء في مرحلة من حياتهن — غالباً بعد الولادة، مع التقدم في السن، أو بسبب التغيرات الهرمونية.',
 'votiva.i1.title': 'شد المهبل',
 'votiva.i1.text': 'بيحسّن الشد والمرونة الداخلية، اللي بتقل بعد الولادة، أو مع السن، أو بسبب التغيرات الهرمونية.',
 'votiva.i2.title': 'سلس البول',
 'votiva.i2.text': 'بيساعد على علاج سلس البول الإجهادي البسيط — التسريب عند الضحك، الكحة، العطس، أو الرياضة.',
 'votiva.i3.title': 'الاستعادة بعد الولادة',
 'votiva.i3.text': 'بيستعيد شد ووظيفة الأنسجة بعد الولادة الطبيعية — خيار طبيعي وغير جراحي للتعافي.',
 'votiva.i4.title': 'الجفاف وعدم الراحة',
 'votiva.i4.text': 'بيحسّن الترطيب والراحة، خاصة في فترة ما حول سن اليأس وسن اليأس.',
 'votiva.i5.title': 'الحساسية والإحساس',
 'votiva.i5.text': 'بيعزّز جودة الأنسجة والإحساس الطبيعي، مما يساهم في الثقة والعلاقة الحميمية.',
 'votiva.i6.title': 'المظهر الخارجي',
 'votiva.i6.text': 'بيحسّن شد ومظهر الجلد الخارجي للمنطقة الحميمية بدون جراحة وبدون فترة نقاهة.',
 'votiva.benefits.eyebrow': 'ليه فوتيفا',
 'votiva.benefits.title': 'الفوائد',
 'votiva.b1': 'معتمد من FDA ومثبت إكلينيكياً للأمان',
 'votiva.b2': 'بدون جراحة بالكامل — بدون شقوق، بدون ندبات',
 'votiva.b3': 'بدون تخدير، مريح طوال الجلسة',
 'votiva.b4': 'جلسات سريعة — عادةً 30 دقيقة',
 'votiva.b5': 'بدون فترة نقاهة — ارجعي لنشاطك اليومي في نفس اليوم',
