 // د. سارة عبدالحميد
 'doctor.sara.name': 'د. سارة عبدالحميد',
 'doctor.sara.role': 'استشاري نحت وتنسيق القوام',
 'doctor.sara.eyebrow': 'استشاري نحت وتنسيق القوام',
 'doctor.sara.tagline': 'استشاري التغذية العلاجية — جامعة القاهرة. استشاري نحت وتنسيق القوام في هوليوود كلينك.',
 'doctor.sara.bio': 'استشاري التغذية العلاجية — جامعة القاهرة. خبرة تتجاوز 15 عاماً وأكثر من 50,000 حالة ناجحة في نحت الجسم بدون جراحة.',
 'doctor.sara.cred1': 'خبرة متخصصة تتجاوز 15 عاماً',
