 'sub.botox.name': 'البوتوكس',
 'sub.botox.eyebrow': 'تجديد البشرة',
 'sub.botox.hero.title': 'البوتوكس',
 'sub.botox.hero.tagline': 'علاج التجاعيد، تجديد ملامح الوجه، وتأخير علامات تقدم السن — بشكل طبيعي.',
 'sub.botox.about.eyebrow': 'نبذة',
 'sub.botox.about.title': 'إيه هو البوتوكس؟',
 'sub.botox.about.body': 'البوتوكس هو حقن بروتين منقّى بيقوم بإرخاء عضلات الوجه المحددة بشكل مؤقت، وبيعمل على فرد التجاعيد الديناميكية — التجاعيد اللي بتظهر مع الابتسامة، العبوس، أو رفع الحواجب. هو من أكثر العلاجات التجميلية دراسةً وانتشارًا حول العالم، وله سجل أمان موثق ممتاز لما يتم تنفيذه على يد طبيب متخصص. داخل هوليوود كلينك، يتم الحقن على يد خبراء معتمدين ومدربين دوليًا. كل جلسة بتسبقها استشارة كاملة وتقييم لملامح الوجه، عشان نصمم جرعة وخريطة حقن مناسبة لتشريحك وأهدافك — مفيش بروتوكول جاهز. البوتوكس مش بس للتجاعيد. بيُستخدم كمان لـ تنحيف الفك، علاج الابتسامة اللثوية، رفع الشفاه (Lip Flip)، شد الرقبة، علاج فرط التعرق، وكذلك لاستخدامات علاجية زي الصداع النصفي المزمن وعلاج طحن الأسنان (Bruxism).',
 'sub.botox.benefits.eyebrow': 'ليه بيشتغل',
 'sub.botox.benefits.title': 'الفوائد والنتائج',
 'sub.botox.benefit.1': 'بيفرد خطوط الجبهة، وخطوط ما بين الحاجبين (11 lines)، والتجاعيد حوالين العين.',
 'sub.botox.benefit.2': 'بيرفع وينعّم منطقة الحاجب عشان مظهر أنضر وأوسع.',
 'sub.botox.benefit.3': 'بينحّف وينعّم خط الفك (Masseter Botox) لنحت ملامح الوش.',
 'sub.botox.benefit.4': 'بيعالج الابتسامة اللثوية، وخطوط الرقبة، ورفع الشفة (Lip Flip).',
 'sub.botox.benefit.5': 'بيعالج فرط التعرق (تحت الإبط أو الكفين).',
 'sub.botox.benefit.6': 'بيقلّل الصداع النصفي (استخدام علاجي).',
