 // ─── DERMAL FILLERS ─── full page content (AR)
 'sub.filler.name': 'الفيلر',
 'sub.filler.eyebrow': 'تجديد البشرة',
 'sub.filler.hero.title': 'الفيلر',
 'sub.filler.hero.tagline': 'استعادة حجم الوجه، نحت الملامح، وشد البشرة — بشكل طبيعي وبدون جراحة.',
 'sub.filler.about.eyebrow': 'نبذة',
 'sub.filler.about.title': 'إيه هو الفيلر؟',
 'sub.filler.about.body': 'الفيلر هو جل قابل للحقن — في الغالب أساسه حمض الهيالورونيك (HA) وهي مادة الجسم بينتجها طبيعيًا — بيعمل على استعادة حجم الوجه، تحديد الملامح، ورفع تركيب الوجه بدون جراحة. مع تقدم السن، تغيرات الوزن، أو العوامل الوراثية، بعض مناطق الوجه بتفقد دعمها وحجمها؛ والفيلر بيعوض ده بطريقة دقيقة ومحكمة. داخل هوليوود كلينك، يتم الحقن على يد خبراء معتمدين باستخدام ماركات عالمية معتمدة فقط. كل جلسة بتبدأ بـ تقييم كامل لملامح الوجه — لأن الفيلر الناجح موضوعه تناسق الوجه، مش مجرد إضافة حجم في منطقة واحدة. يمكن حقن الفيلر في تقريبًا كل مناطق الوجه: الشفاه، الخدود، منتصف الوجه، تحت العين، الأنف (تجميل أنف غير جراحي)، الذقن، الفك، الصدغين، وحتى اليدين والجسم. كل منطقة بتحتاج كثافة فيلر مختلفة وتقنية حقن مختلفة.',
 'sub.filler.benefits.eyebrow': 'ليه بيشتغل',
 'sub.filler.benefits.title': 'الفوائد والنتائج',
 'sub.filler.benefit.1': 'بيرجّع حجم الوش المفقود في الخدود، منتصف الوش، والصدغين.',
 'sub.filler.benefit.2': 'بيكبّر ويعيد تشكيل الشفايف بنتيجة طبيعية.',
