 'sub.filler.reviews.eyebrow': 'آراء العميلات',
 'sub.filler.reviews.title': 'العميلات بيقولوا إيه',
 'sub.filler.doctors.eyebrow': 'الأطباء المتخصصين',
 'sub.filler.doc.view': 'الملف الشخصي',
 'sub.filler.video.eyebrow': 'شوفيه بنفسك',
 'sub.filler.tag.time': 'بيرجّع الحجم والرفع',
