 // ─── SKIN BOOSTERS ─── full page content (AR)
 'sub.skinboosters.name': 'Skin Boosters',
 'sub.skinboosters.eyebrow': 'تجديد البشرة',
 'sub.skinboosters.hero.title': 'Skin Boosters',
 'sub.skinboosters.hero.tagline': 'ترطيب عميق، نضارة دائمة، وتحسين جودة البشرة — من الداخل.',
 'sub.skinboosters.about.eyebrow': 'نبذة',
 'sub.skinboosters.about.title': 'إيه هي Skin Boosters؟',
 'sub.skinboosters.about.body': 'Skin Boosters هي حقن دقيقة (Micro-Injections) من حمض الهيالورونيك النقي غير المتشابك (Non-Cross-Linked) (وأحيانًا فيتامينات وببتيدات ومضادات أكسدة) بيتم حقنها بشكل سطحي داخل البشرة. على عكس الفيلر، هي مش بتعيد التشكيل ولا بتضيف حجم — بترطب البشرة من الداخل، وبتحسن مرونتها، ونعومتها، ونضارتها الطبيعية. اعتبري Skin Boosters بمثابة علاج ترطيب عميق وطويل المدى بيتم توصيله مباشرة للطبقة اللي مش بتقدر تروح لها الكريمات والسيرومات. بتشتغل في طبقة الأدمة، وبتربط الماء، وبتدعم الكولاجين، وبتحوّل جودة البشرة تدريجيًا على مدار سلسلة من الجلسات. داخل هوليوود كلينك، Skin Boosters بتُستخدم للوجه، الرقبة، الصدر، اليدين، وحتى للبشرة اللي فيها آثار حب شباب أو ضرر شمسي — أي مكان البشرة محتاجة تبان أصح، أكثر إشراقًا، وأكثر نضارة.',
 'sub.skinboosters.benefits.eyebrow': 'ليه بيشتغل',
 'sub.skinboosters.benefits.title': 'الفوائد والنتائج',
 'sub.skinboosters.benefit.1': 'ترطيب عميق وطويل المدى من جوّه البشرة.',
 'sub.skinboosters.benefit.2': 'نضارة داخلية واضحة وإشراقة طبيعية.',
 'sub.skinboosters.benefit.3': 'تحسين مرونة البشرة وتماسكها.',
 'sub.skinboosters.benefit.4': 'ملمس أنعم وتوحيد لحبيبات البشرة.',
 'sub.skinboosters.benefit.5': 'تقليل الخطوط الدقيقة والترقّق.',
 'sub.skinboosters.benefit.6': 'لون بشرة أفتح وأكثر توحيدًا.',
 'sub.skinboosters.benefit.7': 'جودة بشرة أحسن في الرقبة وأعلى الصدر وظهر اليدين (مناطق صعب علاجها بطريقة تانية).',
 'sub.skinboosters.benefit.8': 'بيحسّن شكل البشرة المتضررة من الشمس وآثار حب الشباب.',
 'sub.skinboosters.benefit.9': 'نتيجة طبيعية تدريجية — من غير تغييرات مبالغ فيها.',
