    'sub.radiesse.review.7.name': "دعاء إ.",
    'sub.radiesse.review.7.date': "من 3 أسابيع",
    'sub.radiesse.review.7.meta': "Radiesse · أول مرة",
    'sub.radiesse.review.7.text': "نضيف وبإشراف دكتورة وكل حاجة اتشرحت، حتى إنه ما ينفعش يتذوّب. حسّيت إني فاهمة وآمنة.",
 'sub.biostimulators.name': 'Biostimulators',
 'sub.biostimulators.eyebrow': 'تجديد البشرة',
 'sub.biostimulators.hero.title': 'محفزات الكولاجين',
 'sub.biostimulators.hero.tagline': 'تحفيز إنتاج الكولاجين الطبيعي لتجديد بشرة تدريجي وأطول استمرارية.',
 'sub.biostimulators.about.eyebrow': 'نبذة',
 'sub.biostimulators.about.title': 'إيه هي Biostimulators؟',
 'sub.biostimulators.about.body': 'Biostimulators (أو محفزات الكولاجين) هي فئة متقدمة من العلاجات بالحقن بتشتغل بطريقة مختلفة تمامًا عن الفيلر التقليدي. بدل ما تضيف حجم مباشرة، بـ تحفز جسمك لإنتاج كولاجين وإيلاستين جديد وبروتينات هيكلية — وبتعيد بناء أساس البشرة من الداخل تدريجيًا. بتُصنع من مواد متوافقة حيويًا زي حمض البولي لاكتيك (PLLA)، هيدروكسي أباتيت الكالسيوم (CaHA)، أو بولي كابرولاكتون (PCL) — مواد الجسم بيستقلبها تدريجيًا ويستبدلها بكولاجين طبيعي جديد. النتيجة هي تجديد للبشرة \'مش باين إنه اتعمل\'. المريضة بتشوف تحسن تدريجي على مدار أسابيع وشهور، ببشرة بتبقى أكثر شدًا وكثافة ونعومة وأصغر سنًا بشكل واضح — بدون تغييرات مفاجئة في الحجم أو \'وجه فيلر\'. داخل هوليوود كلينك، Biostimulators مخصصة للعملاء اللي عايزين تجديد بشرة بمنهج أكثر تشريحية، أطول مدة، وأكثر طبيعية — واللي عندهم الصبر للانتظار حتى تتطور النتيجة على مدار شهور.',
 'sub.biostimulators.benefits.eyebrow': 'ليه بيشتغل',
 'sub.biostimulators.benefits.title': 'الفوائد والنتائج',
 'sub.biostimulators.benefit.1': 'بيحفّز جسمك إنه ينتج الكولاجين الطبيعي بتاعه.',
 'sub.biostimulators.benefit.2': 'بيحسّن تماسك البشرة وكثافتها ودعمها البنائي.',
 'sub.biostimulators.benefit.3': 'بيعالج ارتخاء البشرة والترقّق عمومًا — مش بس تجاعيد متفرّقة.',
 'sub.biostimulators.benefit.4': 'نتيجة تدريجية طبيعية تشريحيًا — من غير تغييرات حجم مفاجئة.',
 'sub.biostimulators.benefit.5': 'بيرجّع الحجم للمناطق اللي فقدته (الخدود، الصدغين، منتصف الوش).',
 'sub.biostimulators.benefit.6': 'بيقلّل التجاعيد العميقة ويحسّن ملمس البشرة عمومًا.',
 'sub.biostimulators.benefit.7': 'ممتاز لمناطق الجسم (الركب، البطن، الدراع، الرقبة، أعلى الصدر) اللي صعب علاج ارتخائها.',
 'sub.biostimulators.benefit.8': 'بيعالج ارتخاء البشرة بعد فقدان الوزن.',
 'sub.biostimulators.benefit.9': 'تجديد اليدين — بيرجّع الحجم ويحسّن جودة البشرة في ظهر اليد.',
 'sub.biostimulators.benefit.10': 'النتيجة بتدوم من 18 شهر لأكتر من سنتين — أطول بكتير من فيلر الهيالورونيك.',
 'sub.biostimulators.benefit.11': 'متابعة أقل تكرارًا مقارنة بالحقن التانية.',
 'sub.biostimulators.process.eyebrow': 'المراحل',
 'sub.biostimulators.process.title': 'إزاي بتتم الجلسة',
 'sub.biostimulators.step.1.title': 'الاستشارة',
 'sub.biostimulators.step.1.text': 'تقييم كامل للبشرة وتشريح الوجه لتحديد إذا كنتِ مرشحة مناسبة',
 'sub.biostimulators.step.2.title': 'التحضير',
