 'sub.iface.name': 'iFace',
 'sub.iface.eyebrow': 'تجديد البشرة',
 'sub.iface.hero.title': 'iFace لشد الوجه',
 'sub.iface.hero.tagline': 'الجلسة المدمجة الموقّعة من هوليوود كلينك — هيدرافيشيال + فورما في جلسة واحدة. إشراق على السطح، شد من جوّه.',
 'sub.iface.about.eyebrow': 'نبذة',
 'sub.iface.about.title': 'إيه هو iFace؟',
 'sub.iface.about.body': 'iFace هو علاج هوليوود كلينك المميز اللي بيجمع بين اتنين من أكثر الإجراءات التجميلية الطبية احترامًا في العالم — الهيدرافيشيال والفورما — في زيارة واحدة، عشان يدّيكي تحوّل سطحي وشد عميق للبشرة في نفس الجلسة. الدمج ده مقصود: الهيدرافيشيال بتنظف، تقشّر، ترطّب، وتحقن سيرومات مخصصة في البشرة، والفورما بتستخدم الترددات الراديوية المحكومة لتسخين الطبقات العميقة وتحفيز إنتاج الكولاجين والإيلاستين — وشد البشرة من جوّه. النتيجة شيء جلسة واحدة لوحدها مش هتقدر تدّيكي إياه: بشرة فورًا أكثر إشراقًا، أنضف، ومرطّبة على السطح، ومع شد، رفع، ومظهر شبابي من تحت. كل ده في زيارة واحدة بدون فترة نقاهة.',
 'sub.iface.benefits.eyebrow': 'ليه بيشتغل',
 'sub.iface.benefits.title': 'الفوائد والنتائج',
 'sub.iface.benefit.1': 'من مكوّن الهيدرافيشيال: تنظيف عميق وتقشير لطيف.',
 'sub.iface.benefit.2': 'إزالة الشوائب والرؤوس السودا من غير ألم.',
 'sub.iface.benefit.3': 'نضارة فورية واضحة.',
 'sub.iface.benefit.4': 'ترطيب عميق بحقن حمض الهيالورونيك.',
 'sub.iface.benefit.5': 'مسام أدق وملمس بشرة أنعم.',
 'sub.iface.benefit.6': 'لون بشرة أفتح وأكثر توحيدًا.',
 'sub.iface.benefit.7': 'من مكوّن الفورما: تحفيز الكولاجين والإيلاستين الطبيعي.',
 'sub.iface.benefit.8': 'بشرة أكثر شدًّا وتماسكًا في الوش وخط الفك والرقبة.',
